#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#define DIM 4096
#define ITER 1000

int main() {
    float *data = (float*)malloc(DIM * DIM * sizeof(float));
    float *new_data = (float*)malloc(DIM * DIM * sizeof(float));
    if (!data || !new_data) {
        fprintf(stderr, "Failed to allocate memory\n");
        return 1;
    }

    // Initialize data
    #pragma omp parallel for
    for (int i = 0; i < DIM * DIM; i++) {
        data[i] = 0.0f;
        new_data[i] = 0.0f;
    }

    // Set boundary conditions
    #pragma omp parallel for
    for (int i = 0; i < DIM; i++) {
        data[i] = 100.0f;               // top row
        data[(DIM - 1) * DIM + i] = 100.0f; // bottom row
        data[i * DIM] = 100.0f;        // left column
        data[i * DIM + DIM - 1] = 100.0f; // right column

        new_data[i] = 100.0f;
        new_data[(DIM - 1) * DIM + i] = 100.0f;
        new_data[i * DIM] = 100.0f;
        new_data[i * DIM + DIM - 1] = 100.0f;
    }

    for (int iter = 0; iter < ITER; iter++) {
        #pragma omp parallel for
        for (int i = 1; i < DIM - 1; i++) {
            for (int j = 1; j < DIM - 1; j++) {
                int idx = i * DIM + j;
                new_data[idx] = 0.25f * (data[(i - 1) * DIM + j] +
                                        data[(i + 1) * DIM + j] +
                                        data[i * DIM + j - 1] +
                                        data[i * DIM + j + 1]);
            }
        }

        // swap pointers
        float *temp = data;
        data = new_data;
        new_data = temp;
    }

    // Print some values for verification
    printf("Center value: %f\n", data[(DIM / 2) * DIM + (DIM / 2)]);

    free(data);
    free(new_data);
    return 0;
}
